<?php
namespace App\Controllers;
use App\Core\Controller; use App\Models\AuthModel; use App\Models\BaseCatalog;
class AuthController extends Controller { public function login():void{ if(current_user()) redirect('dashboard'); $this->view('auth/login'); } public function authenticate():void{ verify_csrf(); $m=new AuthModel; $u=$m->byLogin(trim($_POST['login']??'')); if($u && password_verify($_POST['password']??'',$u['password'])){ session_regenerate_id(true); refresh_csrf_token(); $_SESSION['user']=['id'=>$u['id'],'nombre'=>$u['nombre'].' '.$u['apellido'],'rol'=>$u['rol'],'rol_id'=>$u['rol_id']]; $_SESSION['permissions']=$m->permissions((int)$u['rol_id']); (new BaseCatalog)->audit('Login','Autenticación',(int)$u['id'],'Ingreso correcto'); redirect('dashboard'); } flash('error','Credenciales inválidas o usuario inactivo.'); redirect('login'); } public function logout():void{ session_destroy(); redirect('login'); }}
